package com.chaobo.scm.supplier.domain.qualification;
import com.chaobo.scm.common.error.*;import com.chaobo.scm.supplier.domain.shared.*;import java.time.*;import java.util.*;
public final class SupplierQualificationAggregate {private final long id;private final long supplierId;private final String type;private final String number;private final LocalDate from;private final LocalDate to;private final String attachment;private QualificationStatus status;private String remark;private int version;private final List<DomainEvent> events=new ArrayList<>();private SupplierQualificationAggregate(long id,long supplierId,String type,String number,LocalDate from,LocalDate to,String attachment,QualificationStatus status,String remark,int version){this.id=id;this.supplierId=supplierId;this.type=type;this.number=number;this.from=from;this.to=to;this.attachment=attachment;this.status=status;this.remark=remark;this.version=version;valid();}
public static SupplierQualificationAggregate submit(long supplierId,String type,String number,LocalDate from,LocalDate to,String attachment,long operator,IdentifierGenerator ids){var a=new SupplierQualificationAggregate(ids.nextId(),supplierId,type,number,from,to,attachment,QualificationStatus.PENDING,null,0);a.raise(ids,"SupplierQualificationSubmitted","供应商资质已提交",operator,Map.of("supplierId",supplierId,"qualificationType",type,"validTo",to.toString()));return a;}public static SupplierQualificationAggregate rehydrate(long id,long supplierId,String type,String number,LocalDate from,LocalDate to,String attachment,int status,String remark,int version){return new SupplierQualificationAggregate(id,supplierId,type,number,from,to,attachment,QualificationStatus.fromCode(status),remark,version);}public void approve(String remark,long operator,IdentifierGenerator ids){require(QualificationStatus.PENDING);if(to.isBefore(LocalDate.now()))throw rule("已过期资质不能审核通过");status=QualificationStatus.VALID;this.remark=remark;version++;raise(ids,"SupplierQualificationApproved","供应商资质已审核通过",operator,Map.of("supplierId",supplierId,"qualificationType",type,"validTo",to.toString()));}public void reject(String reason,long operator,IdentifierGenerator ids){require(QualificationStatus.PENDING);if(reason==null||reason.isBlank())throw rule("驳回原因不能为空");status=QualificationStatus.REJECTED;remark=reason.trim();version++;raise(ids,"SupplierQualificationRejected","供应商资质已驳回",operator,Map.of("supplierId",supplierId,"reason",remark));}public void expire(long operator,IdentifierGenerator ids){if(status!=QualificationStatus.VALID||to.isAfter(LocalDate.now()))return;status=QualificationStatus.EXPIRED;version++;raise(ids,"SupplierQualificationExpired","供应商资质已到期",operator,Map.of("supplierId",supplierId,"qualificationType",type,"validTo",to.toString()));}private void valid(){if(supplierId<=0||type==null||type.isBlank()||number==null||number.isBlank()||attachment==null||attachment.isBlank()||from==null||to==null||to.isBefore(from))throw rule("资质信息不完整或有效期不合法");}private void require(QualificationStatus expected){if(status!=expected)throw new BusinessException(ErrorCode.STATE_CONFLICT,"资质状态不允许当前操作");}private void raise(IdentifierGenerator ids,String eventType,String name,long operator,Map<String,Object> payload){long event=ids.nextId();events.add(new DomainEvent(event,"SUP-"+event,eventType,name,"SUPPLIER_QUALIFICATION",id,Long.toString(id),version,operator,OffsetDateTime.now(),payload));}private static BusinessException rule(String value){return new BusinessException(ErrorCode.BUSINESS_RULE_FAILED,value);}public List<DomainEvent> pullEvents(){var result=List.copyOf(events);events.clear();return result;}public long id(){return id;}public long supplierId(){return supplierId;}public String type(){return type;}public String number(){return number;}public LocalDate from(){return from;}public LocalDate to(){return to;}public String attachment(){return attachment;}public QualificationStatus status(){return status;}public String remark(){return remark;}public int version(){return version;}}
